// Auto-generated: subsetted Noto Sans (Latin + Indian Rupee sign U+20B9)
// embedded as base64 so jsPDF can render ₹ and all receipt text correctly.
// The standard PDF core fonts (Helvetica, etc.) that jsPDF ships with do
// NOT include a glyph for the Rupee sign or for emoji, which is why the
// old receipt showed broken characters like "¹" instead of "₹" and
// garbled bytes instead of icons. This subset keeps the file small
// (~50KB per weight) while covering everything the receipt needs.

export const NOTO_SANS_REGULAR_BASE64 = '';
export const NOTO_SANS_BOLD_BASE64 = '';

/**
 * Registers the embedded Noto Sans font with a jsPDF document instance.
 * Call once per document, before using font family 'NotoSans'.
 * @param {import('jspdf').jsPDF} doc
 */
export function registerNotoSansFonts(doc) {
  doc.addFileToVFS('NotoSans-Regular.ttf', NOTO_SANS_REGULAR_BASE64);
  doc.addFont('NotoSans-Regular.ttf', 'NotoSans', 'normal');

  doc.addFileToVFS('NotoSans-Bold.ttf', NOTO_SANS_BOLD_BASE64);
  doc.addFont('NotoSans-Bold.ttf', 'NotoSans', 'bold');
}